#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *A = (int*)malloc(N * sizeof(int));
        for(int i=1;i<=N;i++){
            if(i%2==1){
                A[i-1] = i;
                if(i+1<=N) A[i] = 2*i;
            }
        }
        for(int i=0;i<N;i++){
            if(i) printf(" ");
            printf("%d", A[i]);
        }
        printf("\n");
        free(A);
    }
    return 0;
}

