import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = [0] * N
        for i in range(1, N + 1):
            if i % 2 == 1:  # odd index (1‑based)
                A[i - 1] = i
                if i + 1 <= N:
                    A[i] = 2 * i
        out_lines.append(' '.join(map(str, A)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

